import os

def parse_theta_results(fname):
    with open(fname) as handle:
        header = next(handle).rstrip().split('\t')
        body = next(handle).rstrip().split('\t')
        assert len(body) == len(header) == 4
        nll = float(body[0])
        mu = body[1].split(',')
        mu_normal = float(mu[0])
        mu_tumors = list(map(float, mu[1:]))
        # Parse C
        c_groups_str = body[2].split(':')
        c_groups = [group.split(',') for group in c_groups_str]
        for group in c_groups:
            if len(group) != len(mu_tumors):
                raise ValueError("Number of tumor fractions does not match number of copy number groups")
        def int_or_none(s):
            try:
                return int(s) if s.isdigit() else None
            except:
                return None
        if len(mu_tumors) == 1:
            copies = [ [int_or_none(val) for group in c_groups for val in group] ]
        else:
            copies = [ [int_or_none(c_groups[j][i]) for j in range(len(c_groups))] for i in range(len(mu_tumors)) ]
        # Parse p*
        p_groups_str = body[3].split(':')
        p_groups = [group.split(',') for group in p_groups_str]
        for group in p_groups:
            if len(group) != len(mu_tumors):
                raise ValueError("Number of tumor fractions does not match number of probability groups")
        def float_or_none(s):
            try:
                return float(s) if not s.isalpha() else None
            except:
                return None
        if len(mu_tumors) == 1:
            probs = [float_or_none(val) for group in p_groups for val in group]
        else:
            probs = [ [float_or_none(p_groups[j][i]) for j in range(len(p_groups))] for i in range(len(mu_tumors)) ]
        return {'NLL': nll, 'mu_normal': mu_normal, 'mu_tumors': mu_tumors, 'C': copies, 'p*': probs}

def main():
    sample = (
        "NLL\tmu\tC\tp*\n"
        "12.5\t0.4,0.6\t2:3\t0.1,0.2\n"
    )
    fname = "theta_test.txt"
    with open(fname, "w") as f:
        f.write(sample)
    result = parse_theta_results(fname)
    print(result)
    os.remove(fname)

if __name__ == "__main__":
    main()
